import{_ as p,o as t,c as a,ai as n}from"./chunks/framework.B1-4-q7d.js";const d=JSON.parse('{"title":"关于征集“人工智能+农业”典型应用场景的通知2026-04-20","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"关于征集“人工智能+农业”典型应用场景的通知2026-04-20","date":"2026-04-20T00:00:00.000Z","source":"农业农村部市场与信息化司","category":"policies","link":"https://scs.moa.gov.cn/gzdt/202604/t20260420_6483397.htm","summary":"各省、自治区、直辖市农业农村（农牧）、渔业厅（局、委），新疆生产建设兵团农业农村局\\n，\\n有关单位\\n：\\n为\\n深入实施“\\n人工智能+\\n”行动，\\n进\\n一步推动\\n《农业农村部关于大力发展智慧农业的指导意见》《全国智慧农业行动计划（2024\\n—\\n2028年）》落地，\\n农业农村部市场与信息化司\\n决定\\n在全国\\n征集\\n发布一批\\n“人工智能\\n+农业\\n”\\n典型\\n应用场景\\n，\\n示范引领各地“人工智能\\n+\\n...\\n","contentHash":"fdb0dfa961df12113b9ba0ff3ff03f24","tags":["智慧农业","政策法规"]},"headers":[],"relativePath":"policies/2026-04-20-关于征集-人工智能-农业-典型应用场景的通知.md","filePath":"policies/2026-04-20-关于征集-人工智能-农业-典型应用场景的通知.md"}'),_={name:"policies/2026-04-20-关于征集-人工智能-农业-典型应用场景的通知.md"};function r(s,e,o,l,i,c){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="关于征集-人工智能-农业-典型应用场景的通知2026-04-20" tabindex="-1">关于征集“人工智能+农业”典型应用场景的通知2026-04-20 <a class="header-anchor" href="#关于征集-人工智能-农业-典型应用场景的通知2026-04-20" aria-label="Permalink to &quot;关于征集“人工智能+农业”典型应用场景的通知2026-04-20&quot;">​</a></h1><blockquote><p>来源: <a href="https://scs.moa.gov.cn/gzdt/202604/t20260420_6483397.htm" target="_blank" rel="noreferrer">农业农村部市场与信息化司</a><br> 日期: 2026-04-20 摘要: 各省、自治区、直辖市农业农村（农牧）、渔业厅（局、委），新疆生产建设兵团农业农村局 ， 有关单位 ： 为 深入实施“ 人工智能+ ”行动， 进 一步推动 《农业农村部关于大力发展智慧农业的指导意见》《全国智慧农业行动计划（2024 — 2028年）》落地， 农业农村部市场与信息化司 决定 在全国 征集 发布一批 “人工智能 +农业 ” 典型 应用场景 ， 示范引领各地“人工智能</p></blockquote><ul><li></li></ul><p>...</p><p>各省、自治区、直辖市农业农村（农牧）、渔业厅（局、委），新疆生产建设兵团农业农村局，有关单位：</p><p>为深入实施“人工智能+”行动，进一步推动《农业农村部关于大力发展智慧农业的指导意见》《全国智慧农业行动计划（2024—2028年）》落地，农业农村部市场与信息化司决定在全国征集发布一批“人工智能+农业”典型应用场景，示范引领各地“人工智能+农业”加快发展。现将有关要求通知如下。</p><p>一、重点场景方向</p><p>以“人工智能+农业”为主线，聚焦农业农村管理服务、农业科学研究、农业生产经营等场景，鼓励单点突破、小切口深应用、可复制可推广的人工智能创新实践。具体内容如下：</p><p>（一）农业农村管理服务场景：利用人工智能技术提升农业农村领域政务管理服务和乡村治理效能，如政务服务智能填报导办、惠农政策智能问答、农业综合执法智能监管、人居环境智能监测等。</p><p>（二）农业科学研究场景：利用人工智能技术加速科研创新，如智能设计育种、AI辅助疫苗研发等。</p><p>（三）农业生产经营场景：利用人工智能技术赋能全产业链提质增效，如智慧种植、精准养殖、病虫害发生规律智能预测、供应链智能调度与溯源、市场需求预测与产销精准对接等。</p><p>二、推荐条件</p><p>（一）场景需要使用了人工智能技术，并在申报场景中发挥了关键作用，取得了较好的效益，对各地具有可借鉴、可复制、可推广价值，不得杜撰和虚报。</p><p>（二）材料聚焦所在场景，重点突出、数据准确，文字表述简明流畅。</p><p>（三）申报主体须具有良好社会声誉，遵纪守法、诚实守信，未被列入经营异常名录、失信名单，核心技术、成果无权属纠纷。</p><p>三、推荐程序</p><p>各省级农业农村部门要认真组织开展本地区场景征集推荐工作，组织申报单位参照《“人工智能+农业”典型应用场景（模板）》（见附件1）准备材料，并对材料的真实性和质量进行审核把关。开展场景实地核验工作，并参照《“人工智能+农业”典型应用场景核验意见（模板）》（见附件2）出具推荐意见。每个省份可推荐的场景不多于10个。推荐场景确定后，请各省级农业农村部门填写《“人工智能+农业”典型应用场景汇总表》（见附件3），并将汇总表、场景材料以及对应的推荐意见等材料于2026年5月15日前书面报送至农业农村部市场与信息化司（电子版发送至xtkfc@agri.gov.cn，需提供扫描版、可编辑电子版各1份）。部直属单位、有关中央企业、国家智慧农业创新中心及分中心可直接推荐不多于5个场景，材料及核验要求同上。</p><p>农业农村部市场与信息化司将组织专家对各地推荐场景进行研究推荐，并随机抽取部分场景开展核验。入选场景将在2026年全国智慧农业现场推进会上发布，并以适当形式向社会公开宣传。</p><p>联系人：许阳010-59191655</p><p>李春朋010-59191697</p><p>附件：　1.“人工智能+农业”典型应用场景（模板）</p><p>2.“人工智能+农业”典型应用场景核验意见（模板）</p><p>3.“人工智能+农业”典型应用场景汇总表</p><p>农业农村部市场与信息化司</p><p>2026年4月20日</p><p><a href="https://scs.moa.gov.cn/gzdt/202604/t20260420_6483397.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',26)])])}const m=p(_,[["render",r]]);export{d as __pageData,m as default};
